// ============================================================
// STATUS COMMAND — reads from Airtable (paginated) + Google Sheets toggle
// ============================================================
const AIRTABLE_PAT = 'YOUR_AIRTABLE_PAT';
const BASE_ID = 'YOUR_AIRTABLE_BASE_ID';
const LEADS_TABLE = 'YOUR_LEADS_TABLE_ID';

try {
  // Paginate through ALL records
  let allLeads = [];
  let offset = null;

do {
    let endpoint = `https://api.airtable.com/v0/${BASE_ID}/${LEADS_TABLE}?fields[]=Status&fields[]=Emailed&pageSize=100`;
    if (offset) endpoint += `&offset=${encodeURIComponent(offset)}`;

    const data = await this.helpers.httpRequest({
      method: 'GET',
      url: endpoint,
      headers: {
        'Authorization': `Bearer ${AIRTABLE_PAT}`
      }
    });

    if (!data || !data.records) {
      throw new Error('No records returned from Airtable — check your PAT and Base ID');
    }

    allLeads = allLeads.concat(data.records);
    offset = data.offset || null;

  } while (offset);

  const total      = allLeads.length;
  const newLeads   = allLeads.filter(r => r.fields.Status === 'New Lead').length;
  const contacted  = allLeads.filter(r => r.fields.Status === 'Contacted').length;
  const interested = allLeads.filter(r => r.fields.Status === 'Interested').length;
  const closed     = allLeads.filter(r => r.fields.Status === 'Closed').length;

  // Read Email Active toggle from Google Sheets
  const settings = $input.all();
  let active = 'Unknown';
  for (const row of settings) {
    if (row.json.Settings === 'Email Active') {
      active = row.json.Value;
      break;
    }
  }

  const statusEmoji = active === 'Yes' ? '🟢 ACTIVE' : (active === 'No' ? '🔴 PAUSED' : '⚪ UNKNOWN');

  return [{
    json: {
      message: `📊 <b>Pipeline Status</b>\n\n📋 Total leads: ${total}\n🆕 New leads: ${newLeads}\n📬 Contacted: ${contacted}\n🔥 Interested: ${interested}\n✅ Closed: ${closed}\n\n⚡ Email outreach: ${statusEmoji}`
    }
  }];

} catch(e) {
  return [{ json: { message: `❌ Status error: ${e.message}` } }];
}

// ============================================================
// QUALIFICATION PRE-FILTER
// Pulls places from Google Maps and filters to businesses that
// match the Working Class AI ideal customer profile:
//   - Must have a website
//   - Must be OPERATIONAL
//   - Must have at least 10 reviews (established business)
//   - Must have a rating of 3.5+ (healthy, active business)
// This saves Firecrawl credits by skipping junk leads early.
// ============================================================

const places = $('Google Maps API').item.json.places;

if (!places || places.length === 0) {
  return [];
}

const filtered = places.filter(place => {
  // Must have a website to scrape
  if (!place.websiteUri) return false;

  // Must be an active, open business
  if (place.businessStatus && place.businessStatus !== 'OPERATIONAL') return false;

  // Must have at least 10 reviews — signals an established business with real customers
  // and enough revenue to have a budget for our services
  if (place.userRatingCount !== undefined && place.userRatingCount < 10) return false;

  // Must have a rating of 3.5 or higher — filters out dying or poorly-run businesses
  // that likely don't have budget or are not worth targeting
  if (place.rating !== undefined && place.rating < 3.5) return false;

  return true;
});

return filtered.map(place => ({ json: place }));

