// ============================================================
// PARSE LLM RESPONSE
// Safely parses the Gemini JSON output and extracts all
// qualification fields. Falls back gracefully on any parse error.
// ============================================================

const raw = $input.item.json.text || '';
const cleaned = raw.replace(/```json|```/gi, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    email: 'Not Found',
    name: 'Not Found',
    company_size: 'Unknown',
    years_in_business: 'Unknown',
    multi_location: 'No',
    hiring_signal: 'No',
    call_volume_signal: 'Unknown',
    qualification_score: 1,
    qualification_notes: 'Could not parse website content — review manually.'
  };
}

return {
  json: {
    email: parsed.email || 'Not Found',
    name: parsed.name || 'Not Found',
    company_size: parsed.company_size || 'Unknown',
    years_in_business: String(parsed.years_in_business || 'Unknown'),
    multi_location: parsed.multi_location || 'No',
    hiring_signal: parsed.hiring_signal || 'No',
    call_volume_signal: parsed.call_volume_signal || 'Unknown',
    qualification_score: parsed.qualification_score || 1,
    qualification_notes: parsed.qualification_notes || ''
  }
};

